# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <limits>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>
#include <numeric>
#include <array>
#include <cstring>

const int MAX_N = 200;
const int MAX_M = 10;
const int MAX_STACK_SIZE = 220;

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();

struct RandomGenerator {
    std::mt19937 rng;
    RandomGenerator() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int an_int(int lo, int hi) {
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double a_double(double lo, double hi) {
        return std::uniform_real_distribution<double>(lo, hi)(rng);
    }
} RGen;

double elapsed_seconds() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct State {
    int stacks[MAX_M][MAX_STACK_SIZE];
    int stack_size[MAX_M];
    int box_stack[MAX_N]; // which stack
    int box_height[MAX_N]; // position in stack
    long long energy;
    int N, M;

    void init(int n, int m, const std::vector<std::vector<int>>& initial_stacks) {
        N = n; M = m; energy = 0;
        for (int i = 0; i < M; i++) {
            stack_size[i] = initial_stacks[i].size();
            for (int j = 0; j < stack_size[i]; j++) {
                int box = initial_stacks[i][j] - 1; // 0-indexed
                stacks[i][j] = box;
                box_stack[box] = i;
                box_height[box] = j;
            }
        }
    }

    void move_block(int first_box, int num_boxes, int dest) {
        int src = box_stack[first_box];
        int src_h = box_height[first_box];
        int dest_h = stack_size[dest];

        for (int i = 0; i < num_boxes; i++) {
            int box = stacks[src][src_h + i];
            stacks[dest][dest_h + i] = box;
            box_stack[box] = dest;
            box_height[box] = dest_h + i;
        }
        stack_size[src] = src_h;
        stack_size[dest] = dest_h + num_boxes;
        energy += num_boxes + 1;
    }

    void carry_out(int box) {
        int s = box_stack[box];
        stack_size[s]--;
    }
};

struct Operation {
    int box_1indexed;
    int dest_1indexed; // 0 for carry-out
};

// Evaluate a destination choice for moving a block
// Returns a score (lower is better)
double evaluate_dest(const State& S, int target, int dest, int src, int src_h, int num_on_top) {
    double score = 0.0;
    int N = S.N;

    // Penalty for covering soon-needed boxes already in destination
    for (int j = 0; j < S.stack_size[dest]; j++) {
        int box_in_dest = S.stacks[dest][j];
        if (box_in_dest > target && box_in_dest < target + 20) {
            // boxes_above = (current stack height) + num_on_top - j
            int boxes_above_after = (S.stack_size[dest] - 1 - j) + num_on_top;
            double urgency = 20.0 / (box_in_dest - target); // higher urgency for closer targets
            score += urgency * boxes_above_after * 0.5;
        }
    }

    // Penalty for soon-needed boxes in the block being buried
    for (int i = 0; i < num_on_top; i++) {
        int box_in_block = S.stacks[src][src_h + 1 + i];
        if (box_in_block > target && box_in_block < target + 20) {
            int boxes_above_in_block = num_on_top - 1 - i;
            int boxes_above_after = boxes_above_in_block + S.stack_size[dest]; // wait, no
            // After move, box_in_block will be at position stack_size[dest] + i
            // Total stack height after = stack_size[dest] + num_on_top
            // boxes above it = (stack_size[dest] + num_on_top) - (stack_size[dest] + i) - 1 = num_on_top - i - 1
            int final_boxes_above = num_on_top - 1 - i;
            double urgency = 20.0 / (box_in_block - target);
            score += urgency * final_boxes_above * 0.5;
        }
    }

    // Bonus for empty stacks (preserve them)
    if (S.stack_size[dest] == 0) {
        score += 50.0; // penalty for using empty stacks frivolously
    }

    // Small penalty for tall destination stacks (spreads load)
    score += S.stack_size[dest] * 0.3;

    // Bonus if the block's soon-needed boxes will be on top
    // Specifically check if the TOP of the moved block is a soon-needed box
    int top_of_block = S.stacks[src][src_h + num_on_top]; // last box in the block (will be on top)
    if (top_of_block > target && top_of_block < target + 5) {
        score -= 10.0; // bonus: soon-needed box on top
    }

    return score;
}

int greedy_best_dest(const State& S, int target) {
    int src = S.box_stack[target];
    int h = S.box_height[target];
    int num_on_top = S.stack_size[src] - 1 - h;

    if (num_on_top == 0) return src; // no move needed

    double best_score = 1e18;
    int best_dest = -1;

    for (int d = 0; d < S.M; d++) {
        if (d == src) continue;
        double sc = evaluate_dest(S, target, d, src, h, num_on_top);
        if (sc < best_score) {
            best_score = sc;
            best_dest = d;
        }
    }
    return best_dest;
}

// Simulate the full plan, return energy
long long simulate_plan(const std::vector<std::vector<int>>& initial_stacks,
                        const std::vector<int>& plan, int N, int M) {
    State S;
    S.init(N, M, initial_stacks);

    for (int k = 0; k < N; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;

        if (num_on_top > 0) {
            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;
            int first_box = S.stacks[src][h + 1];
            S.move_block(first_box, num_on_top, dest);
        }
        S.carry_out(k);
    }
    return S.energy;
}

// Simulate from state at step k_start using plan, return total energy
long long simulate_from(State S, const std::vector<int>& plan, int k_start, int N, int M) {
    for (int k = k_start; k < N; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;

        if (num_on_top > 0) {
            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;
            int first_box = S.stacks[src][h + 1];
            S.move_block(first_box, num_on_top, dest);
        }
        S.carry_out(k);
    }
    return S.energy;
}

// Get state at step k (after processing boxes 0..k-1)
State get_state_at(const std::vector<std::vector<int>>& initial_stacks,
                   const std::vector<int>& plan, int k, int N, int M) {
    State S;
    S.init(N, M, initial_stacks);

    for (int i = 0; i < k; i++) {
        int src = S.box_stack[i];
        int h = S.box_height[i];
        int num_on_top = S.stack_size[src] - 1 - h;

        if (num_on_top > 0) {
            int dest = plan[i];
            if (dest == src) dest = (src + 1) % M;
            int first_box = S.stacks[src][h + 1];
            S.move_block(first_box, num_on_top, dest);
        }
        S.carry_out(i);
    }
    return S;
}

// Beam search to generate initial plan
std::vector<int> beam_search(const std::vector<std::vector<int>>& initial_stacks,
                             int N, int M, double time_budget) {
    struct BeamNode {
        State state;
        std::vector<int> plan;
        long long energy;
    };

    int beam_width = 40;

    std::vector<BeamNode> beam(1);
    beam[0].state.init(N, M, initial_stacks);
    beam[0].energy = 0;
    beam[0].plan.reserve(N);

    std::vector<BeamNode> candidates;
    candidates.reserve(beam_width * M);

    for (int k = 0; k < N; k++) {
        if (elapsed_seconds() > time_budget) {
            // Complete remaining greedily from best node
            auto& best = beam[0];
            for (int kk = k; kk < N; kk++) {
                int dest = greedy_best_dest(best.state, kk);
                best.plan.push_back(dest);
                int src = best.state.box_stack[kk];
                int h = best.state.box_height[kk];
                int num_on_top = best.state.stack_size[src] - 1 - h;
                if (num_on_top > 0) {
                    int actual_dest = dest;
                    if (actual_dest == src) actual_dest = (src + 1) % M;
                    int first_box = best.state.stacks[src][h + 1];
                    best.state.move_block(first_box, num_on_top, actual_dest);
                }
                best.state.carry_out(kk);
            }
            return best.plan;
        }

        candidates.clear();

        for (auto& node : beam) {
            int src = node.state.box_stack[k];
            int h = node.state.box_height[k];
            int num_on_top = node.state.stack_size[src] - 1 - h;

            if (num_on_top == 0) {
                // Free carry-out
                candidates.push_back(node);
                candidates.back().plan.push_back(src);
                candidates.back().state.carry_out(k);
            } else {
                for (int d = 0; d < M; d++) {
                    if (d == src) continue;
                    candidates.push_back(node);
                    auto& cand = candidates.back();
                    cand.plan.push_back(d);
                    int first_box = cand.state.stacks[src][h + 1];
                    cand.state.move_block(first_box, num_on_top, d);
                    cand.state.carry_out(k);
                }
            }
        }

        // Sort by energy (lower is better)
        std::sort(candidates.begin(), candidates.end(),
                  [](const BeamNode& a, const BeamNode& b) {
                      return a.state.energy < b.state.energy;
                  });

        beam.clear();
        int width = std::min(beam_width, (int)candidates.size());
        for (int i = 0; i < width; i++) {
            beam.push_back(std::move(candidates[i]));
        }
    }

    std::sort(beam.begin(), beam.end(),
              [](const BeamNode& a, const BeamNode& b) {
                  return a.state.energy < b.state.energy;
              });
    return beam[0].plan;
}

// Enhanced beam search: use heuristic evaluation (energy + future cost estimate)
std::vector<int> beam_search_heuristic(const std::vector<std::vector<int>>& initial_stacks,
                                        int N, int M, double time_budget) {
    struct BeamNode {
        State state;
        std::vector<int> plan;
        double score; // energy + heuristic future cost
    };

    int beam_width = 30;

    std::vector<BeamNode> beam(1);
    beam[0].state.init(N, M, initial_stacks);
    beam[0].score = 0;
    beam[0].plan.reserve(N);

    std::vector<BeamNode> candidates;
    candidates.reserve(beam_width * M);

    auto estimate_future = [&](const State& S, int next_target) -> double {
        // Estimate future cost: for next W boxes, estimate how many are buried
        double cost = 0;
        int W = std::min(10, N - next_target);
        for (int i = 0; i < W; i++) {
            int box = next_target + i;
            int s = S.box_stack[box];
            int h = S.box_height[box];
            int on_top = S.stack_size[s] - 1 - h;
            if (on_top > 0) {
                cost += on_top + 1; // minimum cost to extract this box
            }
        }
        return cost * 0.3; // discounted
    };

    for (int k = 0; k < N; k++) {
        if (elapsed_seconds() > time_budget) {
            auto& best = beam[0];
            for (int kk = k; kk < N; kk++) {
                int dest = greedy_best_dest(best.state, kk);
                best.plan.push_back(dest);
                int src = best.state.box_stack[kk];
                int h = best.state.box_height[kk];
                int num_on_top = best.state.stack_size[src] - 1 - h;
                if (num_on_top > 0) {
                    int actual_dest = dest;
                    if (actual_dest == src) actual_dest = (src + 1) % M;
                    int first_box = best.state.stacks[src][h + 1];
                    best.state.move_block(first_box, num_on_top, actual_dest);
                }
                best.state.carry_out(kk);
            }
            return best.plan;
        }

        candidates.clear();

        for (auto& node : beam) {
            int src = node.state.box_stack[k];
            int h = node.state.box_height[k];
            int num_on_top = node.state.stack_size[src] - 1 - h;

            if (num_on_top == 0) {
                candidates.push_back(node);
                auto& cand = candidates.back();
                cand.plan.push_back(src);
                cand.state.carry_out(k);
                cand.score = cand.state.energy + estimate_future(cand.state, k + 1);
            } else {
                for (int d = 0; d < M; d++) {
                    if (d == src) continue;
                    candidates.push_back(node);
                    auto& cand = candidates.back();
                    cand.plan.push_back(d);
                    int first_box = cand.state.stacks[src][h + 1];
                    cand.state.move_block(first_box, num_on_top, d);
                    cand.state.carry_out(k);
                    cand.score = cand.state.energy + estimate_future(cand.state, k + 1);
                }
            }
        }

        std::sort(candidates.begin(), candidates.end(),
                  [](const BeamNode& a, const BeamNode& b) {
                      return a.score < b.score;
                  });

        beam.clear();
        int width = std::min(beam_width, (int)candidates.size());
        for (int i = 0; i < width; i++) {
            beam.push_back(std::move(candidates[i]));
        }
    }

    std::sort(beam.begin(), beam.end(),
              [](const BeamNode& a, const BeamNode& b) {
                  return a.state.energy < b.state.energy;
              });
    return beam[0].plan;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> initial_stacks(M);
    for (int i = 0; i < M; i++) {
        initial_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
        }
    }

    const double TIME_LIMIT = 1.95;
    const double BEAM_TIME = 0.60; // 60% for beam search

    // Generate initial plan using heuristic beam search
    std::vector<int> best_plan = beam_search_heuristic(initial_stacks, N, M, BEAM_TIME);
    long long best_energy = simulate_plan(initial_stacks, best_plan, N, M);

    // SA phase
    std::vector<int> current_plan = best_plan;
    long long current_energy = best_energy;

    double T_init = 50.0;
    double T_final = 0.01;
    double sa_start = elapsed_seconds();
    double sa_budget = TIME_LIMIT - 0.03 - sa_start;

    if (sa_budget > 0.05) {
        // Checkpoints: store states at regular intervals
        const int CHECKPOINT_INTERVAL = 10;
        int num_checkpoints = (N + CHECKPOINT_INTERVAL - 1) / CHECKPOINT_INTERVAL;
        std::vector<State> checkpoints(num_checkpoints + 1);

        auto rebuild_checkpoints = [&](const std::vector<int>& plan) {
            checkpoints[0].init(N, M, initial_stacks);
            for (int cp = 0; cp < num_checkpoints; cp++) {
                int start = cp * CHECKPOINT_INTERVAL;
                int end = std::min(start + CHECKPOINT_INTERVAL, N);
                if (cp == 0) {
                    // checkpoint[0] is initial state
                } else {
                    checkpoints[cp] = checkpoints[cp - 1];
                    int prev_start = (cp - 1) * CHECKPOINT_INTERVAL;
                    int prev_end = start;
                    for (int k = prev_start; k < prev_end; k++) {
                        int src = checkpoints[cp].box_stack[k];
                        int h = checkpoints[cp].box_height[k];
                        int num_on_top = checkpoints[cp].stack_size[src] - 1 - h;
                        if (num_on_top > 0) {
                            int dest = plan[k];
                            if (dest == src) dest = (src + 1) % M;
                            int first_box = checkpoints[cp].stacks[src][h + 1];
                            checkpoints[cp].move_block(first_box, num_on_top, dest);
                        }
                        checkpoints[cp].carry_out(k);
                    }
                }
            }
            // Actually let's just build all from scratch properly
            State S;
            S.init(N, M, initial_stacks);
            checkpoints[0] = S;
            for (int k = 0; k < N; k++) {
                int src = S.box_stack[k];
                int h = S.box_height[k];
                int num_on_top = S.stack_size[src] - 1 - h;
                if (num_on_top > 0) {
                    int dest = plan[k];
                    if (dest == src) dest = (src + 1) % M;
                    int first_box = S.stacks[src][h + 1];
                    S.move_block(first_box, num_on_top, dest);
                }
                S.carry_out(k);
                if ((k + 1) % CHECKPOINT_INTERVAL == 0) {
                    checkpoints[(k + 1) / CHECKPOINT_INTERVAL] = S;
                }
            }
        };

        rebuild_checkpoints(current_plan);
        int rebuild_count = 0;
        const int REBUILD_INTERVAL = 500; // rebuild checkpoints periodically

        int sa_iter = 0;
        while (true) {
            double now = elapsed_seconds();
            if (now >= TIME_LIMIT - 0.03) break;

            double progress = (now - sa_start) / sa_budget;
            if (progress > 1.0) break;
            double T = T_init * std::pow(T_final / T_init, progress);

            std::vector<int> new_plan = current_plan;

            // Choose perturbation type
            double r = RGen.a_double(0, 1);
            int change_start;

            if (r < 0.4) {
                // Single point change, biased toward earlier indices
                double u = RGen.a_double(0, 1);
                change_start = (int)(u * u * N); // quadratic bias toward 0
                if (change_start >= N) change_start = N - 1;
                new_plan[change_start] = RGen.an_int(0, M - 1);
            } else if (r < 0.75) {
                // Block change
                double u = RGen.a_double(0, 1);
                change_start = (int)(u * u * N);
                if (change_start >= N) change_start = N - 1;
                int len = RGen.an_int(1, std::max(1, N / 10));
                for (int i = 0; i < len && change_start + i < N; i++) {
                    new_plan[change_start + i] = RGen.an_int(0, M - 1);
                }
            } else {
                // Greedy re-optimization at a random point
                double u = RGen.a_double(0, 1);
                change_start = (int)(u * u * N);
                if (change_start >= N) change_start = N - 1;

                // Get state at change_start using checkpoint
                int cp_idx = change_start / CHECKPOINT_INTERVAL;
                int cp_start = cp_idx * CHECKPOINT_INTERVAL;
                State S = checkpoints[cp_idx];
                for (int k = cp_start; k < change_start; k++) {
                    int src = S.box_stack[k];
                    int h = S.box_height[k];
                    int num_on_top = S.stack_size[src] - 1 - h;
                    if (num_on_top > 0) {
                        int dest = current_plan[k];
                        if (dest == src) dest = (src + 1) % M;
                        int first_box = S.stacks[src][h + 1];
                        S.move_block(first_box, num_on_top, dest);
                    }
                    S.carry_out(k);
                }
                new_plan[change_start] = greedy_best_dest(S, change_start);
            }

            // Evaluate new plan using checkpoint
            int cp_idx = change_start / CHECKPOINT_INTERVAL;
            int cp_start = cp_idx * CHECKPOINT_INTERVAL;
            State S = checkpoints[cp_idx];
            for (int k = cp_start; k < change_start; k++) {
                int src = S.box_stack[k];
                int h = S.box_height[k];
                int num_on_top = S.stack_size[src] - 1 - h;
                if (num_on_top > 0) {
                    int dest = current_plan[k]; // use current_plan for prefix (unchanged)
                    if (dest == src) dest = (src + 1) % M;
                    int first_box = S.stacks[src][h + 1];
                    S.move_block(first_box, num_on_top, dest);
                }
                S.carry_out(k);
            }
            long long new_energy = simulate_from(S, new_plan, change_start, N, M);

            long long delta = new_energy - current_energy;
            if (delta < 0 || (T > 1e-9 && RGen.a_double(0, 1) < std::exp(-(double)delta / T))) {
                current_energy = new_energy;
                current_plan = new_plan;
                if (new_energy < best_energy) {
                    best_energy = new_energy;
                    best_plan = new_plan;
                }
                rebuild_count++;
                if (rebuild_count >= REBUILD_INTERVAL) {
                    rebuild_checkpoints(current_plan);
                    rebuild_count = 0;
                }
            }
            sa_iter++;
        }
    }

    // Generate output
    State S;
    S.init(N, M, initial_stacks);
    std::vector<Operation> ops;
    ops.reserve(N * 2);

    for (int k = 0; k < N; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;

        if (num_on_top > 0) {
            int dest = best_plan[k];
            if (dest == src) dest = (src + 1) % M;
            int first_box = S.stacks[src][h + 1];
            ops.push_back({first_box + 1, dest + 1});
            S.move_block(first_box, num_on_top, dest);
        }
        ops.push_back({k + 1, 0});
        S.carry_out(k);
    }

    for (auto& op : ops) {
        std::cout << op.box_1indexed << " " << op.dest_1indexed << "\n";
    }

    return 0;
}
