#include <utility>
#include <numeric>
#include <array>
#include <cstring>

const int MAX_N = 200;
const int MAX_M = 10;
const int MAX_STACK_SIZE = 220;

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();

struct RandomGenerator {
    std::mt19937 rng;
    RandomGenerator() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int an_int(int lo, int hi) {
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double a_double(double lo, double hi) {
        return std::uniform_real_distribution<double>(lo, hi)(rng);
    }
} RGen;

double elapsed_seconds() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct State {
    int stacks[MAX_M][MAX_STACK_SIZE];
    int stack_size[MAX_M];
    int box_stack[MAX_N];
    int box_height[MAX_N];
    long long energy;
    int N, M;

    void init(int n, int m, const std::vector<std::vector<int>>& initial_stacks) {
        N = n; M = m; energy = 0;
        for (int i = 0; i < M; i++) {
            stack_size[i] = initial_stacks[i].size();
            for (int j = 0; j < stack_size[i]; j++) {
                int box = initial_stacks[i][j] - 1;
                stacks[i][j] = box;
                box_stack[box] = i;
                box_height[box] = j;
            }
        }
    }

    void move_block(int first_box, int num_boxes, int dest) {
        int src = box_stack[first_box];
        int src_h = box_height[first_box];
        int dest_h = stack_size[dest];

        for (int i = 0; i < num_boxes; i++) {
            int box = stacks[src][src_h + i];
            stacks[dest][dest_h + i] = box;
            box_stack[box] = dest;
            box_height[box] = dest_h + i;
        }
        stack_size[src] = src_h;
        stack_size[dest] = dest_h + num_boxes;
        energy += num_boxes + 1;
    }

    void carry_out(int box) {
        int s = box_stack[box];
        stack_size[s]--;
    }
};

struct Operation {
    int box_1indexed;
    int dest_1indexed;
};

double elapsed_s;

int greedy_best_dest(const State& S, int target) {
    int src = S.box_stack[target];
    int h = S.box_height[target];
    int num_on_top = S.stack_size[src] - 1 - h;
    int N = S.N, M = S.M;

    if (num_on_top == 0) return src;

    double best_score = 1e18;
    int best_dest = -1;

    for (int d = 0; d < M; d++) {
        if (d == src) continue;
        double score = 0.0;

        // Penalty for covering soon-needed boxes in destination
        for (int j = 0; j < S.stack_size[d]; j++) {
            int box_in_dest = S.stacks[d][j];
            if (box_in_dest > target && box_in_dest < target + 25) {
                int boxes_above_after = (S.stack_size[d] - 1 - j) + num_on_top;
                double urgency = 25.0 / (box_in_dest - target);
                score += urgency * boxes_above_after * 0.8;
            }
        }

        // Penalty for soon-needed boxes in block that will be buried
        for (int i = 0; i < num_on_top; i++) {
            int box_in_block = S.stacks[src][h + 1 + i];
            if (box_in_block > target && box_in_block < target + 25) {
                int final_boxes_above = num_on_top - 1 - i;
                double urgency = 25.0 / (box_in_block - target);
                score += urgency * final_boxes_above * 0.5;
            }
        }

        // Bonus for empty stacks - preserve them
        if (S.stack_size[d] == 0) {
            score += 80.0;
        }

        // Prefer shorter destination stacks
        score += S.stack_size[d] * 0.5;

        // Bonus if top of moved block is soon-needed
        int top_of_block = S.stacks[src][h + num_on_top];
        if (top_of_block > target && top_of_block < target + 5) {
            score -= 15.0;
        }

        if (score < best_score) {
            best_score = score;
            best_dest = d;
        }
    }
    return best_dest;
}

long long simulate_plan(const std::vector<std::vector<int>>& initial_stacks,
                        const std::vector<int>& plan, int N, int M) {
    State S;
    S.init(N, M, initial_stacks);
    for (int k = 0; k < N; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;
        if (num_on_top > 0) {
            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;
            int first_box = S.stacks[src][h + 1];
            S.move_block(first_box, num_on_top, dest);
        }
        S.carry_out(k);
    }
    return S.energy;
}

long long simulate_from(State S, const std::vector<int>& plan, int k_start, int N, int M) {
    for (int k = k_start; k < N; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;
        if (num_on_top > 0) {
            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;
            int first_box = S.stacks[src][h + 1];
            S.move_block(first_box, num_on_top, dest);
        }
        S.carry_out(k);
    }
    return S.energy;
}

State simulate_prefix(const std::vector<std::vector<int>>& initial_stacks,
                      const std::vector<int>& plan, int k, int N, int M) {
    State S;
    S.init(N, M, initial_stacks);
    for (int i = 0; i < k; i++) {
        int src = S.box_stack[i];
        int h = S.box_height[i];
        int num_on_top = S.stack_size[src] - 1 - h;
        if (num_on_top > 0) {
            int dest = plan[i];
            if (dest == src) dest = (src + 1) % M;
            int first_box = S.stacks[src][h + 1];
            S.move_block(first_box, num_on_top, dest);
        }
        S.carry_out(i);
    }
    return S;
}

// Beam search with lookahead heuristic
std::vector<int> beam_search_heuristic(const std::vector<std::vector<int>>& initial_stacks,
                                        int N, int M, double time_budget) {
    struct BeamNode {
        State state;
        std::vector<int> plan;
        double score;
    };

    int beam_width = 30;

    std::vector<BeamNode> beam(1);
    beam[0].state.init(N, M, initial_stacks);
    beam[0].score = 0;
    beam[0].plan.reserve(N);

    std::vector<BeamNode> candidates;
    candidates.reserve(beam_width * M);

    auto estimate_future = [&](const State& S, int next_target) -> double {
        double cost = 0;
        int W = std::min(15, N - next_target);
        for (int i = 0; i < W; i++) {
            int box = next_target + i;
            int s = S.box_stack[box];
            int h = S.box_height[box];
            int on_top = S.stack_size[s] - 1 - h;
            if (on_top > 0) {
                double discount = 1.0 / (1.0 + i * 0.2);
                cost += (on_top + 1) * discount;
            }
        }
        return cost * 0.5;
    };

    for (int k = 0; k < N; k++) {
        if (elapsed_seconds() > time_budget) {
            if (beam.empty()) break;
            std::sort(beam.begin(), beam.end(),
                      [](const BeamNode& a, const BeamNode& b) { return a.score < b.score; });
            auto& best = beam[0];
            for (int kk = k; kk < N; kk++) {
                int dest = greedy_best_dest(best.state, kk);
                best.plan.push_back(dest);
                int src = best.state.box_stack[kk];
                int h = best.state.box_height[kk];
                int num_on_top = best.state.stack_size[src] - 1 - h;
                if (num_on_top > 0) {
                    int actual_dest = dest;
                    if (actual_dest == src) actual_dest = (src + 1) % M;
                    int first_box = best.state.stacks[src][h + 1];
                    best.state.move_block(first_box, num_on_top, actual_dest);
                }
                best.state.carry_out(kk);
            }
            return best.plan;
        }

        candidates.clear();

        for (auto& node : beam) {
            int src = node.state.box_stack[k];
            int h = node.state.box_height[k];
            int num_on_top = node.state.stack_size[src] - 1 - h;

            if (num_on_top == 0) {
                candidates.push_back(node);
                auto& cand = candidates.back();
                cand.plan.push_back(src);
                cand.state.carry_out(k);
                cand.score = cand.state.energy + estimate_future(cand.state, k + 1);
            } else {
                for (int d = 0; d < M; d++) {
                    if (d == src) continue;
                    candidates.push_back(node);
                    auto& cand = candidates.back();
                    cand.plan.push_back(d);
                    int first_box = cand.state.stacks[src][h + 1];
                    cand.state.move_block(first_box, num_on_top, d);
                    cand.state.carry_out(k);
                    cand.score = cand.state.energy + estimate_future(cand.state, k + 1);
                }
            }
        }

        if (candidates.empty()) break;

        std::sort(candidates.begin(), candidates.end(),
                  [](const BeamNode& a, const BeamNode& b) { return a.score < b.score; });

        beam.clear();
        int width = std::min(beam_width, (int)candidates.size());
        for (int i = 0; i < width; i++) {
            beam.push_back(std::move(candidates[i]));
        }
    }

    if (beam.empty()) {
        std::vector<int> plan(N);
        for (int i = 0; i < N; i++) plan[i] = RGen.an_int(0, M - 1);
        return plan;
    }
    std::sort(beam.begin(), beam.end(),
              [](const BeamNode& a, const BeamNode& b) { return a.state.energy < b.state.energy; });
    return beam[0].plan;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> initial_stacks(M);
    for (int i = 0; i < M; i++) {
        initial_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
        }
