// Simulate full plan, return energy. plan[k] = destination for boxes above target k.
long long simulate_plan(const std::vector<std::vector<int>>& initial_stacks,
                        const int* plan, int N, int M) {
    State S;
    S.init(N, M, initial_stacks);
    for (int k = 0; k < N; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;
        if (num_on_top > 0) {
            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;
            int first_box = S.stacks[src][h + 1];
            S.move_block(first_box, num_on_top, dest);
        }
        S.carry_out(k);
    }
    return S.energy;
}

// Simulate from a given state for the suffix of the plan
long long simulate_suffix(State S, const int* plan, int k_start, int N, int M) {
    for (int k = k_start; k < N; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;
        if (num_on_top > 0) {
            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;
            int first_box = S.stacks[src][h + 1];
            S.move_block(first_box, num_on_top, dest);
        }
        S.carry_out(k);
    }
    return S.energy;
