// Simulate prefix up to step k (process boxes 0..k-1)
State simulate_prefix(const std::vector<std::vector<int>>& initial_stacks,
                      const int* plan, int k, int N, int M) {
    State S;
    S.init(N, M, initial_stacks);
    for (int i = 0; i < k; i++) {
        int src = S.box_stack[i];
        int h = S.box_height[i];
        int num_on_top = S.stack_size[src] - 1 - h;
        if (num_on_top > 0) {
            int dest = plan[i];
            if (dest == src) dest = (src + 1) % M;
            int first_box = S.stacks[src][h + 1];
            S.move_block(first_box, num_on_top, dest);
        }
        S.carry_out(i);
    }
    return S;
}

// Beam search with lookahead heuristic
void beam_search_heuristic(const std::vector<std::vector<int>>& initial_stacks,
                           int N, int M, double time_budget, int* result_plan) {
    struct BeamNode {
        State state;
        int plan[MAX_N];
        double score;
    };

    const int BEAM_WIDTH = 20;

    std::vector<BeamNode> beam(1);
    beam[0].state.init(N, M, initial_stacks);
    beam[0].score = 0;
    beam.reserve(BEAM_WIDTH + 1);

    std::vector<BeamNode> candidates;
    candidates.reserve(BEAM_WIDTH * M + 1);

    auto estimate_future = [&](const State& S, int next_target) -> double {
        double cost = 0;
        int W = std::min(12, N - next_target);
        for (int i = 0; i < W; i++) {
            int box = next_target + i;
            int s = S.box_stack[box];
            int h = S.box_height[box];
            int on_top = S.stack_size[s] - 1 - h;
            if (on_top > 0) {
                double discount = 1.0 / (1.0 + i * 0.25);
                cost += (on_top + 1) * discount;
            }
        }
        return cost * 0.5;
    };

    for (int k = 0; k < N; k++) {
        if (elapsed_seconds() > time_budget) {
            // Complete greedily from best
            if (beam.empty()) break;
            std::sort(beam.begin(), beam.end(),
                      [](const BeamNode& a, const BeamNode& b) { return a.score < b.score; });
            auto& best = beam[0];
            for (int kk = k; kk < N; kk++) {
                int dest = greedy_best_dest(best.state, kk);
                best.plan[kk] = dest;
                int src = best.state.box_stack[kk];
                int h = best.state.box_height[kk];
                int num_on_top = best.state.stack_size[src] - 1 - h;
                if (num_on_top > 0) {
                    int actual_dest = dest;
                    if (actual_dest == src) actual_dest = (src + 1) % M;
                    int first_box = best.state.stacks[src][h + 1];
                    best.state.move_block(first_box, num_on_top, actual_dest);
                }
                best.state.carry_out(kk);
            }
            memcpy(result_plan, best.plan, sizeof(int) * N);
            return;
        }

        candidates.clear();

        for (auto& node : beam) {
            int src = node.state.box_stack[k];
            int h = node.state.box_height[k];
            int num_on_top = node.state.stack_size[src] - 1 - h;

            if (num_on_top == 0) {
                candidates.push_back(node);
                auto& cand = candidates.back();
                cand.plan[k] = src;
                cand.state.carry_out(k);
                cand.score = cand.state.energy + estimate_future(cand.state, k + 1);
            } else {
                for (int d = 0; d < M; d++) {
                    if (d == src) continue;
                    candidates.push_back(node);
                    auto& cand = candidates.back();
                    cand.plan[k] = d;
                    int first_box = cand.state.stacks[src][h + 1];
                    cand.state.move_block(first_box, num_on_top, d);
                    cand.state.carry_out(k);
                    cand.score = cand.state.energy + estimate_future(cand.state, k + 1);
                }
            }
        }

        if (candidates.empty()) break;

        std::sort(candidates.begin(), candidates.end(),
                  [](const BeamNode& a, const BeamNode& b) { return a.score < b.score; });

        beam.clear();
        int width = std::min(BEAM_WIDTH, (int)candidates.size());
        for (int i = 0; i < width; i++) {
            beam.push_back(std::move(candidates[i]));
        }
    }

    if (beam.empty()) {
        for (int i = 0; i < N; i++) result_plan[i] = RGen.an_int(0, M - 1);
        return;
    }
    std::sort(beam.begin(), beam.end(),
              [](const BeamNode& a, const BeamNode& b) { return a.state.energy < b.state.energy; });
    memcpy(result_plan, beam[0].plan, sizeof(int) * N);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> initial_stacks(M);
    for (int i = 0; i < M; i++) {
        initial_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
        }
    }

    const double TIME_LIMIT = 1.90;
    const double BEAM_TIME = 0.50;

    int best_plan[MAX_N];
    int current_plan[MAX_N];

    // Generate initial plan using heuristic beam search
    beam_search_heuristic(initial_stacks, N, M, BEAM_TIME, best_plan);
    long long best_energy = simulate_plan(initial_stacks, best_plan, N, M);
    memcpy(current_plan, best_plan, sizeof(int) * N);
    long long current_energy = best_energy;

    // SA phase
    double T_init = 40.0;
    double T_final = 0.01;
    double sa_start = elapsed_seconds();
    double sa_budget = TIME_LIMIT - 0.02 - sa_start;

    if (sa_budget > 0.05) {
        int new_plan[MAX_N];

        while (true) {
            double now = elapsed_seconds();
            if (now >= TIME_LIMIT - 0.02) break;

            double progress = (now - sa_start) / sa_budget;
            if (progress > 1.0) break;
            double T = T_init * std::pow(T_final / T_init, progress);

            memcpy(new_plan, current_plan, sizeof(int) * N);
            int change_start = 0;

            double r = RGen.a_double(0, 1);

            if (r < 0.4) {
                double u = RGen.a_double(0, 1);
                change_start = (int)(u * u * N);
                if (change_start >= N) change_start = N - 1;
                new_plan[change_start] = RGen.an_int(0, M - 1);
            } else if (r < 0.75) {
                double u = RGen.a_double(0, 1);
                change_start = (int)(u * u * N);
                if (change_start >= N) change_start = N - 1;
                int len = RGen.an_int(2, std::min(15, N - change_start));
                for (int i = 0; i < len; i++) {
                    new_plan[change_start + i] = RGen.an_int(0, M - 1);
                }
            } else {
                // Greedy re-optimization
                double u = RGen.a_double(0, 1);
                change_start = (int)(u * u * N);
                if (change_start >= N) change_start = N - 1;
                State S = simulate_prefix(initial_stacks, current_plan, change_start, N, M);
                new_plan[change_start] = greedy_best_dest(S, change_start);
            }

            // Evaluate: simulate from change_start
            State S = simulate_prefix(initial_stacks, new_plan, change_start, N, M);
            long long new_energy = simulate_suffix(S, new_plan, change_start, N, M);

            long long delta = new_energy - current_energy;
            if (delta < 0 || (T > 1e-9 && RGen.a_double(0, 1) < std::exp(-(double)delta / T))) {
                current_energy = new_energy;
                memcpy(current_plan, new_plan, sizeof(int) * N);
                if (new_energy < best_energy) {
                    best_energy = new_energy;
                    memcpy(best_plan, new_plan, sizeof(int) * N);
                }
            }
        }
    }

    // Generate output
    State S;
    S.init(N, M, initial_stacks);

    for (int k = 0; k < N; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;

        if (num_on_top > 0) {
            int dest = best_plan[k];
            if (dest == src) dest = (src + 1) % M;
            int first_box = S.stacks[src][h + 1];
            std::cout << (first_box + 1) << " " << (dest + 1) << "\n";
            S.move_block(first_box, num_on_top, dest);
        }
        std::cout << (k + 1) << " 0\n";
        S.carry_out(k);
    }

    return 0;
}
