#include <iostream>
#include <vector>
#include <algorithm>
#include <chrono>
#include <random>
#include <cmath>
#include <cstring>

const int MAX_N = 200;
const int MAX_M = 10;
const int MAX_STACK_SIZE = 220;

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();

struct RandomGenerator {
    std::mt19937 rng;
    RandomGenerator() : rng(42) {}
    void seed_time() { rng.seed(std::chrono::steady_clock::now().time_since_epoch().count()); }
    int an_int(int lo, int hi) {
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double a_double(double lo, double hi) {
        return std::uniform_real_distribution<double>(lo, hi)(rng);
    }
} RGen;

double elapsed_seconds() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct State {
    int stacks[MAX_M][MAX_STACK_SIZE];
    int stack_size[MAX_M];
    int box_stack[MAX_N];
    int box_height[MAX_N];
    long long energy;
    int N, M;

    void init(int n, int m, const std::vector<std::vector<int>>& initial_stacks) {
        N = n; M = m; energy = 0;
        for (int i = 0; i < M; i++) {
            stack_size[i] = (int)initial_stacks[i].size();
            for (int j = 0; j < stack_size[i]; j++) {
                int box = initial_stacks[i][j] - 1;
                stacks[i][j] = box;
                box_stack[box] = i;
                box_height[box] = j;
            }
        }
    }

    inline void move_block(int first_box, int num_boxes, int dest) {
        int src = box_stack[first_box];
        int src_h = box_height[first_box];
        int dest_h = stack_size[dest];
        for (int i = 0; i < num_boxes; i++) {
            int box = stacks[src][src_h + i];
            stacks[dest][dest_h + i] = box;
            box_stack[box] = dest;
            box_height[box] = dest_h + i;
        }
        stack_size[src] = src_h;
        stack_size[dest] = dest_h + num_boxes;
        energy += num_boxes + 1;
    }

    inline void carry_out(int box) {
        stack_size[box_stack[box]]--;
    }
};

int greedy_best_dest(const State& S, int target) {
    int src = S.box_stack[target];
    int h = S.box_height[target];
    int num_on_top = S.stack_size[src] - 1 - h;
    int M = S.M;

    if (num_on_top == 0) return src;

    double best_score = 1e18;
    int best_dest = (src + 1) % M;

    for (int d = 0; d < M; d++) {
        if (d == src) continue;
        double score = 0.0;

        for (int j = 0; j < S.stack_size[d]; j++) {
            int box_in_dest = S.stacks[d][j];
            if (box_in_dest > target && box_in_dest < target + 25) {
                int boxes_above_after = (S.stack_size[d] - 1 - j) + num_on_top;
                double urgency = 25.0 / (box_in_dest - target);
                score += urgency * boxes_above_after * 0.8;
            }
        }

        for (int i = 0; i < num_on_top; i++) {
            int box_in_block = S.stacks[src][h + 1 + i];
            if (box_in_block > target && box_in_block < target + 25) {
                int final_boxes_above = num_on_top - 1 - i;
                double urgency = 25.0 / (box_in_block - target);
                score += urgency * final_boxes_above * 0.5;
            }
        }

        if (S.stack_size[d] == 0) score += 80.0;
        score += S.stack_size[d] * 0.5;

        int top_of_block = S.stacks[src][h + num_on_top];
        if (top_of_block > target && top_of_block < target + 5) {
            score -= 15.0;
        }

        if (score < best_score) { best_score = score; best_dest = d; }
    }
    return best_dest;
}

long long simulate_full(const std::vector<std::vector<int>>& initial_stacks,
                        const int* plan, int N, int M) {
    State S;
    S.init(N, M, initial_stacks);
    for (int k = 0; k < N; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;
        if (num_on_top > 0) {
            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;
            S.move_block(S.stacks[src][h + 1], num_on_top, dest);
        }
        S.carry_out(k);
    }
    return S.energy;
}

// Generate greedy plan from a given state
void greedy_complete(State& S, int* plan, int from, int N) {
    for (int k = from; k < N; k++) {
        plan[k] = greedy_best_dest(S, k);
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;
        if (num_on_top > 0) {
            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;
            S.move_block(S.stacks[src][h + 1], num_on_top, dest);
        }
        S.carry_out(k);
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();
    RGen.seed_time();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> initial_stacks(M);
    for (int i = 0; i < M; i++) {
        initial_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
        }
    }

    const double TIME_LIMIT = 1.85;

    // Phase 1: Beam search with heuristic evaluation
    // Use a simpler approach: just do greedy + SA (the beam search struct copies were too heavy)
    // Pure greedy initial solution
    int best_plan[MAX_N];
    {
        State S;
        S.init(N, M, initial_stacks);
        greedy_complete(S, best_plan, 0, N);
    }
    long long best_energy = simulate_full(initial_stacks, best_plan, N, M);

    // Phase 2: SA with full re-simulation (N=200 is small enough)
    int current_plan[MAX_N];
    memcpy(current_plan, best_plan, sizeof(int) * N);
    long long current_energy = best_energy;

    double T_init = 50.0;
    double T_final = 0.1;
    double sa_start = elapsed_seconds();
    double sa_budget = TIME_LIMIT - sa_start;

    if (sa_budget > 0.01) {
        int new_plan[MAX_N];

        while (true) {
            double now = elapsed_seconds();
            if (now >= TIME_LIMIT) break;

            double progress = (now - sa_start) / sa_budget;
            if (progress > 1.0) break;
            double T = T_init * std::pow(T_final / T_init, progress);

            memcpy(new_plan, current_plan, sizeof(int) * N);

            double r = RGen.a_double(0, 1);

            if (r < 0.4) {
                // Single point change
                int idx = RGen.an_int(0, N - 1);
                new_plan[idx] = RGen.an_int(0, M - 1);
            } else if (r < 0.7) {
                // Block change
                int idx = RGen.an_int(0, N - 1);
                int len = RGen.an_int(2, std::min(12, N - idx));
                for (int i = 0; i < len; i++) {
                    new_plan[idx + i] = RGen.an_int(0, M - 1);
                }
            } else if (r < 0.85) {
                // Swap two entries
                int i1 = RGen.an_int(0, N - 1);
                int i2 = RGen.an_int(0, N - 1);
                std::swap(new_plan[i1], new_plan[i2]);
            } else {
                // Greedy at a random point (with prefix from current plan)
                int idx = RGen.an_int(0, N - 1);
                State S;
                S.init(N, M, initial_stacks);
                for (int k = 0; k < idx; k++) {
                    int src = S.box_stack[k];
                    int h = S.box_height[k];
                    int num_on_top = S.stack_size[src] - 1 - h;
                    if (num_on_top > 0) {
                        int dest = current_plan[k];
                        if (dest == src) dest = (src + 1) % M;
                        S.move_block(S.stacks[src][h + 1], num_on_top, dest);
                    }
                    S.carry_out(k);
                }
                new_plan[idx] = greedy_best_dest(S, idx);
            }

            long long new_energy = simulate_full(initial_stacks, new_plan, N, M);

            long long delta = new_energy - current_energy;
            if (delta <= 0 || RGen.a_double(0, 1) < std::exp(-(double)delta / T)) {
                current_energy = new_energy;
                memcpy(current_plan, new_plan, sizeof(int) * N);
                if (new_energy < best_energy) {
                    best_energy = new_energy;
                    memcpy(best_plan, new_plan, sizeof(int) * N);
                }
            }
        }
    }

    // Output
    State S;
    S.init(N, M, initial_stacks);
    for (int k = 0; k < N; k++) {
