        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double a_double(double lo, double hi) {
        return std::uniform_real_distribution<double>(lo, hi)(rng);
    }
} RGen;

double elapsed_seconds() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct State {
    int stacks[MAX_M][MAX_STACK_SIZE];
    int stack_size[MAX_M];
    int box_stack[MAX_N];
    int box_height[MAX_N];
    long long energy;
    int N, M;

    void init(int n, int m, const std::vector<std::vector<int>>& initial_stacks) {
        N = n; M = m; energy = 0;
        for (int i = 0; i < M; i++) {
            stack_size[i] = (int)initial_stacks[i].size();
            for (int j = 0; j < stack_size[i]; j++) {
                int box = initial_stacks[i][j] - 1;
                stacks[i][j] = box;
                box_stack[box] = i;
                box_height[box] = j;
            }
        }
    }

    bool move_block(int first_box, int num_boxes, int dest) {
        int src = box_stack[first_box];
        int src_h = box_height[first_box];
        int dest_h = stack_size[dest];
        if (dest_h + num_boxes >= MAX_STACK_SIZE) return false;
        for (int i = 0; i < num_boxes; i++) {
            int box = stacks[src][src_h + i];
            stacks[dest][dest_h + i] = box;
            box_stack[box] = dest;
            box_height[box] = dest_h + i;
        }
        stack_size[src] = src_h;
        stack_size[dest] = dest_h + num_boxes;
        energy += num_boxes + 1;
        return true;
    }

