            int dest = plan[k];
            if (dest == src) dest = (src + 1) % M;
            if (!S.move_block(S.stacks[src][h + 1], num_on_top, dest)) {
                return 1e9;
            }
        }
        S.carry_out(k);
    }
    return S.energy;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();
