int greedy_best_dest(const State& S, int target) {
    int src = S.box_stack[target];
    int h = S.box_height[target];
    int num_on_top = S.stack_size[src] - 1 - h;
    int N = S.N, M = S.M;

    if (num_on_top == 0) return src;

    double best_score = 1e18;
    int best_dest = (src + 1) % M;

    // Count empty stacks available
    int empty_count = 0;
    for (int d = 0; d < M; d++) {
        if (d != src && S.stack_size[d] == 0) empty_count++;
    }

    for (int d = 0; d < M; d++) {
        if (d == src) continue;
        double score = 0.0;

        // Penalty for covering soon-needed boxes in destination
        for (int j = 0; j < S.stack_size[d]; j++) {
            int box_in_dest = S.stacks[d][j];
            if (box_in_dest > target && box_in_dest < target + 30) {
                int boxes_above_after = (S.stack_size[d] - 1 - j) + num_on_top;
                double urgency = 30.0 / (box_in_dest - target);
                score += urgency * boxes_above_after * 1.0;
            }
        }

        // Penalty for burying soon-needed boxes in block
        for (int i = 0; i < num_on_top; i++) {
            int box_in_block = S.stacks[src][h + 1 + i];
            if (box_in_block > target && box_in_block < target + 30) {
                int final_boxes_above = num_on_top - 1 - i;
                double urgency = 30.0 / (box_in_block - target);
                score += urgency * final_boxes_above * 0.6;
            }
        }

        // Empty stack handling - preserve at least 1 empty stack
        if (S.stack_size[d] == 0) {
            if (empty_count <= 1) {
                score += 150.0; // strongly preserve last empty stack
            } else {
                score += 20.0; // mild preference to avoid using empties
            }
        }

        // Prefer shorter stacks
        score += S.stack_size[d] * 0.4;

        // Bonus if top of moved block is soon-needed (will be accessible)
        int top_of_block = S.stacks[src][h + num_on_top];
        if (top_of_block > target && top_of_block < target + 5) {
            score -= 20.0;
        }

        // Bonus if the block would be placed in order (sorted) on dest
        if (S.stack_size[d] > 0) {
            int dest_top = S.stacks[d][S.stack_size[d] - 1];
            int block_bottom = S.stacks[src][h + 1];
            if (block_bottom > dest_top && dest_top > target) {
                score -= 5.0; // reward stacking in ascending order from bottom
            }
        }

        if (score < best_score) { best_score = score; best_dest = d; }
    }
    return best_dest;
}

